import{_ as n,C as s,o,c as l,a4 as a,E as i}from"./chunks/framework.DyvFOq6U.js";const h=JSON.parse('{"title":"互動沙盒 / Interactive Sandbox","description":"","frontmatter":{"title":"互動沙盒 / Interactive Sandbox","layout":"page"},"headers":[],"relativePath":"sandbox/index.md","filePath":"sandbox/index.md","lastUpdated":null}'),r={name:"sandbox/index.md"};function d(p,t,c,b,g,_){const e=s("SandboxEditor");return o(),l("div",null,[t[0]||(t[0]=a('<h1 id="互動沙盒-interactive-sandbox" tabindex="-1">互動沙盒 / Interactive Sandbox <a class="header-anchor" href="#互動沙盒-interactive-sandbox" aria-label="Permalink to &quot;互動沙盒 / Interactive Sandbox&quot;">​</a></h1><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文</span><p>這是一個<strong>瀏覽器內 Typst 即時編譯器</strong>！無需安裝任何軟體，直接在左側輸入 Typst 程式碼，右側將即時顯示 SVG 向量輸出。</p><p><strong>支援的功能</strong>：完整 Typst 語法（文字、標題、列表、表格、數學公式）、即時預覽。</p><p><strong>注意</strong>：沙盒無法載入外部圖片或自訂字型。如需完整功能，請使用 <a href="https://typst.app/play/" target="_blank" rel="noreferrer">Typst 線上編輯器</a>。</p></div><div class="en-block"><span class="lang-label">English</span><p>This is an <strong>in-browser Typst live compiler</strong>! Type Typst code on the left and see the SVG output on the right in real time, no installation needed.</p><p><strong>Supported</strong>: Full Typst syntax (text, headings, lists, tables, math), real-time preview.</p><p><strong>Note</strong>: The sandbox cannot load external images or custom fonts. For full functionality, use the <a href="https://typst.app/play/" target="_blank" rel="noreferrer">Typst Online Editor</a>.</p></div></div><hr>',3)),i(e),t[1]||(t[1]=a('<hr><h2 id="沙盒使用技巧-sandbox-tips" tabindex="-1">沙盒使用技巧 / Sandbox Tips <a class="header-anchor" href="#沙盒使用技巧-sandbox-tips" aria-label="Permalink to &quot;沙盒使用技巧 / Sandbox Tips&quot;">​</a></h2><div class="bilingual-block"><div class="zh-block"><span class="lang-label">中文</span><ul><li>編輯器支援 <strong>語法高亮</strong> 和 <strong>自動換行</strong></li><li>輸入代碼後 <strong>0.4 秒</strong> 自動編譯預覽</li><li>可以從教學頁面複製範例代碼到沙盒中實驗</li><li>SVG 輸出可以右鍵下載</li></ul></div><div class="en-block"><span class="lang-label">English</span><ul><li>Editor supports basic text editing and word wrap</li><li>Code auto-compiles and previews after a <strong>0.4 second</strong> delay</li><li>Copy example code from tutorial pages to experiment in the sandbox</li><li>SVG output can be right-clicked to download</li></ul></div></div>',3))])}const u=n(r,[["render",d]]);export{h as __pageData,u as default};
